import React, { useState, useEffect } from 'react';
import api from '../services/api';

export default function ReportModal({ patient, measurements, onClose }) {
  const [templates, setTemplates] = useState([]);
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [customPrompt, setCustomPrompt] = useState('');
  const [includeChart, setIncludeChart] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [sending, setSending] = useState(false);
  const [report, setReport] = useState(null);
  const [editedText, setEditedText] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [step, setStep] = useState('compose'); // compose | preview

  useEffect(() => {
    api.get('/messaging/templates').then(r => {
      setTemplates(r.data);
      if (r.data.length > 0) setSelectedTemplate(r.data[0]);
    }).catch(() => {});
  }, []);

  const effectivePrompt = customPrompt.trim() || selectedTemplate?.text || '';

  const generate = async () => {
    if (!effectivePrompt) { setError('Please select or write a prompt.'); return; }
    setError('');
    setGenerating(true);
    try {
      const res = await api.post('/messaging/generate-report', {
        patient_id: patient.id,
        prompt: effectivePrompt,
        include_chart: includeChart,
      });
      setReport(res.data);
      setEditedText(res.data.report_text);
      setStep('preview');
    } catch (e) {
      const err = e.response?.data;
      if (err?.retry) {
        setError('GapGPT AI service is temporarily unavailable. Please retry.');
      } else {
        setError(err?.error || 'Failed to generate report.');
      }
    } finally {
      setGenerating(false);
    }
  };

  const send = async () => {
    setSending(true);
    setError('');
    try {
      await api.post('/messaging/send', {
        patient_id: patient.id,
        message: editedText,
        chart_base64: report?.chart_base64 || null,
      });
      setSuccess('✅ Message sent successfully via Bale!');
      setTimeout(onClose, 2000);
    } catch (e) {
      setError(e.response?.data?.error || 'Failed to send message. Check your Bale bot token.');
    } finally {
      setSending(false);
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal modal-lg" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <h2>📊 Report & Send — {patient.name}</h2>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>

        <div className="modal-body">
          {error && (
            <div className="alert alert-error">
              ⚠ {error}
              {error.includes('retry') && (
                <button className="btn btn-sm btn-warning" style={{ marginLeft: 10 }} onClick={generate}>
                  🔄 Retry
                </button>
              )}
            </div>
          )}
          {success && <div className="alert alert-success">{success}</div>}

          {step === 'compose' ? (
            <>
              <div className="form-group">
                <label className="form-label">Preset Prompts</label>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, marginBottom: 8 }}>
                  {templates.map(t => (
                    <button
                      key={t.id}
                      className={`btn btn-sm ${selectedTemplate?.id === t.id ? 'btn-primary' : 'btn-ghost'}`}
                      onClick={() => { setSelectedTemplate(t); setCustomPrompt(''); }}
                    >
                      {t.label}
                    </button>
                  ))}
                </div>
                {selectedTemplate && !customPrompt && (
                  <div className="alert alert-info" style={{ fontSize: 12 }}>
                    {selectedTemplate.text}
                  </div>
                )}
              </div>

              <div className="form-group">
                <label className="form-label">Custom Prompt (overrides preset)</label>
                <textarea
                  className="form-textarea"
                  rows={4}
                  placeholder="Write your custom prompt here, or leave blank to use the selected preset above…"
                  value={customPrompt}
                  onChange={e => setCustomPrompt(e.target.value)}
                />
              </div>

              <label className="checkbox-label mb-16">
                <input
                  type="checkbox"
                  checked={includeChart}
                  onChange={e => setIncludeChart(e.target.checked)}
                  disabled={measurements.length < 2}
                />
                Generate progress chart image {measurements.length < 2 && <span className="text-muted">(requires 2+ measurements)</span>}
              </label>
            </>
          ) : (
            <>
              {report?.chart_base64 && (
                <div style={{ textAlign: 'center', marginBottom: 16 }}>
                  <img
                    src={`data:image/png;base64,${report.chart_base64}`}
                    alt="Progress chart"
                    style={{ maxWidth: '100%', borderRadius: 'var(--radius)', border: '1px solid var(--gray-200)' }}
                  />
                </div>
              )}

              <div className="form-group">
                <label className="form-label">Message Text (editable before sending)</label>
                <textarea
                  className="form-textarea"
                  rows={10}
                  value={editedText}
                  onChange={e => setEditedText(e.target.value)}
                  style={{ fontFamily: 'inherit', lineHeight: 1.7 }}
                />
              </div>

              <div className="alert alert-info">
                📲 Will be sent to <strong>{patient.name}</strong> via Bale (Chat ID: {patient.bale_chat_id})
              </div>
            </>
          )}
        </div>

        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={step === 'compose' ? onClose : () => setStep('compose')}>
            {step === 'compose' ? 'Cancel' : '← Back'}
          </button>

          {step === 'compose' ? (
            <button className="btn btn-primary" onClick={generate} disabled={generating}>
              {generating ? <><span className="spinner" /> Generating with AI…</> : '✨ Generate Report'}
            </button>
          ) : (
            <button className="btn btn-success" onClick={send} disabled={sending || !!success}>
              {sending ? <><span className="spinner" /> Sending…</> : '📤 Confirm & Send via Bale'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
